// Validate Stripe payment webhook data
const data = $input.first().json;

// Extract payment information
const paymentData = {
  paymentIntentId: data.payment_intent?.id || data.paymentIntentId,
  amount: data.payment_intent?.amount || data.amount,
  currency: data.payment_intent?.currency || data.currency,
  status: data.payment_intent?.status || data.status,
  metadata: data.payment_intent?.metadata || data.metadata,
  customerEmail: data.payment_intent?.receipt_email || data.metadata?.email,
  timestamp: new Date().toISOString()
};

// Validate required fields
const errors = [];
if (!paymentData.paymentIntentId) errors.push('Missing payment intent ID');
if (!paymentData.amount) errors.push('Missing payment amount');
if (!paymentData.metadata?.email) errors.push('Missing customer email');
if (!paymentData.metadata?.leadCount) errors.push('Missing lead count');
if (!paymentData.metadata?.targetLeads) errors.push('Missing target leads');

if (errors.length > 0) {
  return [{
    json: {
      success: false,
      errors: errors,
      message: 'Payment validation failed'
    }
  }];
}

// Calculate pricing breakdown
const leadCount = parseInt(paymentData.metadata.leadCount);
const price = parseFloat(paymentData.metadata.price);
const pricePerLead = (price / leadCount).toFixed(2);

return [{
  json: {
    success: true,
    paymentData,
    leadCount,
    price,
    pricePerLead,
    tier: paymentData.metadata.tier || 'professional',
    customerData: {
      firstName: paymentData.metadata.firstName,
      lastName: paymentData.metadata.lastName,
      email: paymentData.metadata.email,
      businessDescription: paymentData.metadata.businessDescription,
      targetLeads: paymentData.metadata.targetLeads
    }
  }
}];

// Parse and enrich the generated leads
const perplexityResponse = $input.first().json;
const customerData = $('Validate Payment Data').first().json.customerData;
const leadCount = $('Validate Payment Data').first().json.leadCount;

let leads = [];

try {
  // Extract leads from Perplexity response
  const content = perplexityResponse.choices[0].message.content;

  // Try to parse as JSON
  const jsonMatch = content.match(/\[([\s\S]*?)\]/);
  if (jsonMatch) {
    leads = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback: parse text format
    const lines = content.split('\n').filter(line => line.trim());
    leads = lines.slice(0, leadCount).map((line, index) => ({
      name: `Lead ${index + 1}`,
      company: 'Company Name',
      title: 'Professional Title',
      description: line.trim(),
      source: 'AI Generated'
    }));
  }
} catch (error) {
  console.error('Lead parsing error:', error);
  // Create sample leads as fallback
  leads = Array.from({ length: Math.min(leadCount, 10) }, (_, index) => ({
    name: `Sample Lead ${index + 1}`,
    company: 'Sample Company',
    title: 'Marketing Professional',
    description: `AI-generated lead for ${customerData.targetLeads}`,
    source: 'AI Generated (Fallback)'
  }));
}

// Enrich each lead with AI analysis
const enrichedLeads = leads.map((lead, index) => {
  return {
    id: `lead_${Date.now()}_${index}`,
    name: lead.name || `Lead ${index + 1}`,
    company: lead.company || 'Company Name',
    title: lead.title || 'Professional Title',
    email: lead.email || `${lead.name?.toLowerCase().replace(/\s+/g, '.')}@company.com`,
    linkedin: lead.linkedin || `https://linkedin.com/in/${lead.name?.toLowerCase().replace(/\s+/g, '-')}`,
    description: lead.description || `Professional in ${customerData.targetLeads}`,
    source: lead.source || 'AI Generated',
    enrichedAt: new Date().toISOString(),
    customerEmail: customerData.email,
    targetCriteria: customerData.targetLeads,
    businessContext: customerData.businessDescription
  };
});

return enrichedLeads.map(lead => ({ json: lead }));

